import React from "react";

export default function ColorDisplay({ color, onColorChange }) {
  return (
    <div className="color-display-rectangle" style={{ background: color }}>
      <input
        type="color"
        className="color-display-input"
        value={color}
        onChange={e => onColorChange(e.target.value)}
        aria-label="Pick a color"
      />
    </div>
  );
}
